// Extract form data and file from merge node, normalize structure for downstream processing
const data = $input.first().json;
const binaryData = $input.first().binary;

if (!binaryData || Object.keys(binaryData).length === 0) {
  throw new Error('No file uploaded. Please ensure the form includes a PDF attachment.');
}

const firstFileKey = Object.keys(binaryData)[0];
const file = binaryData[firstFileKey];

if (!file || !file.fileName) {
  throw new Error('Invalid file data. Please upload a valid PDF file.');
}

return {
  json: {
    name: data['Your Name'] || 'User',
    email: data['Your Email'] || '',
    contractType: data['Contract Type'] || 'Unknown',
    fileName: file.fileName || 'contract.pdf',
    fileSize: file.fileSize || 0,
    timestamp: new Date().toISOString()
  },
  binary: {
    data: file
  }
};

// Extract PDF text, truncate to 40k chars, and merge with user data for AI analysis
const extractedData = $input.first();
const userData = $('Extract Form Data').first().json;
const text = extractedData.json.text || '';

const maxChars = 40000;
const truncatedText = text.length > maxChars 
  ? text.substring(0, maxChars) + '\n\n[Document truncated for analysis]' 
  : text;

const wordCount = text.split(/\s+/).length;
const pageEstimate = Math.ceil(wordCount / 300);

return {
  json: {
    name: userData.name,
    email: userData.email,
    contractType: userData.contractType,
    fileName: userData.fileName,
    fileSize: userData.fileSize,
    contractText: truncatedText,
    wordCount: wordCount,
    estimatedPages: pageEstimate,
    timestamp: userData.timestamp
  }
};

// Parse AI outputs (translation + risk), assign color-coded risk labels, merge into final report structure
const userData = $('Clean & Truncate Text').first().json;
const translation = $('Translate to Plain English').first().json;
const riskAssessment = $('Calculate Risk Score').first().json;

let parsedTranslation, parsedRisk;

try {
  const tText = translation.output || JSON.stringify(translation);
  parsedTranslation = JSON.parse(tText.trim().replace(/```json/g, '').replace(/```/g, ''));
} catch (e) {
  parsedTranslation = {
    documentTitle: userData.contractType,
    summary: "Analysis unavailable",
    sections: [],
    redFlags: [{clause: "Analysis failed", concern: "Please try again", severity: "medium"}],
    keyObligations: {yourObligations: [], theirObligations: []}
  };
}

try {
  const rText = riskAssessment.output || JSON.stringify(riskAssessment);
  parsedRisk = JSON.parse(rText.trim().replace(/```json/g, '').replace(/```/g, ''));
} catch (e) {
  parsedRisk = {
    overallRiskScore: 50,
    riskLevel: "medium",
    riskExplanation: "Analysis unavailable",
    biggestRisks: ["Unable to assess"],
    recommendLawyer: true
  };
}

const riskScore = parsedRisk.overallRiskScore || 50;
let riskColor, riskLabel;

if (riskScore >= 86) {
  riskColor = "#ef4444";
  riskLabel = "CRITICAL RISK";
} else if (riskScore >= 61) {
  riskColor = "#f97316";
  riskLabel = "HIGH RISK";
} else if (riskScore >= 31) {
  riskColor = "#f59e0b";
  riskLabel = "MEDIUM RISK";
} else {
  riskColor = "#10b981";
  riskLabel = "LOW RISK";
}

return {
  json: {
    name: userData.name,
    email: userData.email,
    contractType: userData.contractType,
    documentTitle: parsedTranslation.documentTitle,
    parties: parsedTranslation.parties || {},
    summary: parsedTranslation.summary,
    sections: parsedTranslation.sections || [],
    redFlags: parsedTranslation.redFlags || [],
    yourObligations: parsedTranslation.keyObligations?.yourObligations || [],
    theirObligations: parsedTranslation.keyObligations?.theirObligations || [],
    terminationRights: parsedTranslation.terminationRights || "Not specified",
    disputeResolution: parsedTranslation.disputeResolution || "Not specified",
    riskScore: riskScore,
    riskLevel: parsedRisk.riskLevel || "medium",
    riskColor: riskColor,
    riskLabel: riskLabel,
    riskExplanation: parsedRisk.riskExplanation,
    biggestRisks: parsedRisk.biggestRisks || [],
    recommendLawyer: parsedRisk.recommendLawyer || false,
    lawyerReason: parsedRisk.lawyerReason || "",
    analyzedAt: new Date().toISOString()
  }
};
